parameters.jsonBody:
={
  "contents": [
    {
      "parts": [
        {
          "text": "You are a pro SEO copywriter and localized marketing strategist for Benin City, Edo State and Nigeria. Write a comprehensive, SEO-optimized blog article about: '" + $json.body.keyword + "'. Tone: '" + ($json.body.tone || "informative") + "'. Length: '" + ($json.body.postLength || "medium") + "'. Always write structured, compelling content with clear headers and bullet points. Include relevant local landmarks, culture, and context from Benin City (like Oba Market, GRA, UNIBEN, King's Square, Ring Road, Edo Tech Hub) to ensure authenticity and state-of-the-art positioning. Provide actionable insights on earning through AI or mastering digital tutorials. You MUST respond with a raw JSON object with exactly these keys: 'title' (compelling title containing the target keyword), 'contentHtml' (beautified, detailed HTML article with headings and paragraphs), 'excerpt' (short 2-sentence summary/meta description), 'tags' (array of 3-5 tags). Output raw JSON only: do not wrap in markdown block style triple-backticks."
        }
      ]
    }
  ],
  "generationConfig": {
    "responseMimeType": "application/json"
  }
}

parameters.jsCode:
try {
  let text = $json.candidates[0].content.parts[0].text.trim();
  const b = String.fromCharCode(96);
  const bt3 = b + b + b;
  if (text.startsWith(bt3 + 'json')) {
    text = text.slice(7);
  } else if (text.startsWith(bt3)) {
    text = text.slice(3);
  }
  if (text.endsWith(bt3)) {
    text = text.slice(0, -3);
  }
  const articleData = JSON.parse(text.trim());
  return {
    json: {
      parsed: true,
      title: articleData.title,
      contentHtml: articleData.contentHtml,
      excerpt: articleData.excerpt,
      tags: articleData.tags || []
    }
  };
} catch (e) {
  return {
    json: {
      parsed: false,
      rawResponse: $json,
      error: e.message
    }
  };
}

return {
  json: {
    status: "failed",
    message: "Could not parse Gemini API response. Check raw text payloads.",
    error: $json.error
  }
};
